import QtQuick
import QtQuick.Controls

Menu {
    id: menu
    MenuItem {
        text: qsTr(&quot;New...&quot;)
    }
    MenuItem {
        text: qsTr(&quot;Open...&quot;)
    }
    MenuItem {
        text: qsTr(&quot;Save&quot;)
    }

    MenuSeparator {
        padding: 0
        topPadding: 12
        bottomPadding: 12
        contentItem: Rectangle {
            implicitWidth: 200
            implicitHeight: 1
            color: &quot;#1E000000&quot;
        }
    }

    MenuItem {
        text: qsTr(&quot;Exit&quot;)
    }
}
